+        let lcp = sa.lcp_array();
+
+        for (i, &val) in lcp.iter().enumerate() {
+            // usize is inherently non-negative, but verify no logical overflow
+            prop_assert!(val <= text.len(), "LCP[{}] = {} exceeds text length {}", i, val, text.len());
+        }
+    }
